mapper.select:
SELECT * FROM (
  SELECT a.*, ROWNUM rn FROM (
    SELECT om.user_id, u.name, om.role, om.created_at
    FROM org_members om
    JOIN users u ON om.user_id = u.id
    WHERE om.org_id = #{orgId}
    ORDER BY om.created_at DESC
  ) a
  WHERE ROWNUM <= #{endRow}
)
WHERE rn > #{startRow}
